class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.plotDiv = document.createElement('div');
        this.plotDiv.style.width = '100%';
        this.plotDiv.style.height = '100%';
        this.plotDiv.style.minHeight = '500px';
        this.container.appendChild(this.plotDiv);
        this.initialized = false;
    }

    getSteps(inputs) {
        const alphaRad = (inputs.angle * Math.PI) / 180;
        const H = inputs.height;
        const result = (2 * Math.PI * H * Math.log(1 / Math.cos(alphaRad))).toFixed(4);

        return [
            {
                title: "The Region V",
                description: `The region $V$ is a solid cone with height $H = ${H}$ and a half-angle $\\alpha = ${inputs.angle}^\\circ$. The boundary is defined by $x^2 + y^2 \\le z^2 \\tan^2(${inputs.angle}^\\circ)$ and $0 \\le z \\le ${H}$.` 
            },
            {
                title: "Coordinate Transformation",
                description: "We transform to spherical coordinates: $x = \\rho \\sin\\phi \\cos\\theta$, $y = \\rho \\sin\\phi \\sin\\theta$, $z = \\rho \\cos\\phi$. The integrand $\\frac{1}{x^2+y^2+z^2}$ becomes $\\frac{1}{\\rho^2}$."
            },
            {
                title: "Angular Bounds",
                description: `The azimuthal angle $\\theta$ sweeps a full circle: $0 \\le \\theta \\le 2\\pi$. The polar angle $\\phi$ is bounded by the cone's slope: $0 \\le \\phi \\le ${inputs.angle}^\\circ$.` 
            },
            {
                title: "Radial Bounds",
                description: `The radial distance $\\rho$ starts at the origin and ends at the top cap $z = H$. Since $z = \\rho \\cos\\phi$, the upper bound is $\\rho = H \\sec\\phi = ${H} \\sec\\phi$.` 
            },
            {
                title: "The Integral Setup",
                description: "The volume element is $dV = \\rho^2 \\sin\\phi d\\rho d\\phi d\\theta$. The integral becomes: $$I = \\int_{0}^{2\\pi} \\int_{0}^{\\alpha} \\int_{0}^{H \\sec\\phi} \\sin\\phi \\, d\\rho \\, d\\phi \\, d\\theta$$"
            },
            {
                title: "Final Calculation",
                description: `Evaluating the inner integral gives $H \\sec\\phi \\sin\\phi = H \\tan\\phi$. Integrating $H \\tan\\phi$ gives $H \\ln|\\sec\\phi|$. Final result: $I = 2\\pi H \\ln(\\sec\\alpha) \\approx ${result}$.` 
            }
        ];
    }

    render(inputs, stepIndex) {
        const alpha = (inputs.angle * Math.PI) / 180;
        const H = inputs.height;
        const opacity = inputs.opacity;
        const data = [];

        // 1. Generate Cone Surface
        const n = 50;
        const m = 20;
        let x_cone = [], y_cone = [], z_cone = [];
        for (let i = 0; i <= m; i++) {
            let r_row = [], g_row = [], b_row = [];
            let z_val = (i / m) * H;
            let r_val = z_val * Math.tan(alpha);
            for (let j = 0; j <= n; j++) {
                let theta = (j / n) * 2 * Math.PI;
                x_cone.push(r_val * Math.cos(theta));
                y_cone.push(r_val * Math.sin(theta));
                z_cone.push(z_val);
            }
        }

        data.push({
            type: 'mesh3d',
            x: x_cone,
            y: y_cone,
            z: z_cone,
            alphahull: -1,
            opacity: opacity,
            color: '#3b82f6',
            name: 'Cone Surface',
            showscale: false
        });

        // 2. Generate Top Cap
        let x_cap = [], y_cap = [], z_cap = [];
        const R_max = H * Math.tan(alpha);
        for (let i = 0; i <= m; i++) {
            let r_val = (i / m) * R_max;
            for (let j = 0; j <= n; j++) {
                let theta = (j / n) * 2 * Math.PI;
                x_cap.push(r_val * Math.cos(theta));
                y_cap.push(r_val * Math.sin(theta));
                z_cap.push(H);
            }
        }

        data.push({
            type: 'mesh3d',
            x: x_cap,
            y: y_cap,
            z: z_cap,
            alphahull: -1,
            opacity: opacity,
            color: '#60a5fa',
            name: 'Top Cap',
            showscale: false
        });

        // 3. Step-specific overlays
        if (stepIndex >= 1) {
            // Draw Z-axis (height)
            data.push({
                type: 'scatter3d',
                mode: 'lines+text',
                x: [0, 0], y: [0, 0], z: [0, H * 1.2],
                line: { color: '#f8fafc', width: 4 },
                text: ['', 'Z'],
                name: 'Z-axis'
            });
        }

        if (stepIndex === 2 || stepIndex === 3) {
            // Draw Phi angle arc
            const phi_arc_x = [], phi_arc_y = [], phi_arc_z = [];
            const arc_r = H * 0.5;
            for (let p = 0; p <= alpha; p += 0.05) {
                phi_arc_x.push(0);
                phi_arc_y.push(arc_r * Math.sin(p));
                phi_arc_z.push(arc_r * Math.cos(p));
            }
            data.push({
                type: 'scatter3d',
                mode: 'lines',
                x: phi_arc_x, y: phi_arc_y, z: phi_arc_z,
                line: { color: '#f59e0b', width: 6 },
                name: 'Phi Angle'
            });
        }

        if (stepIndex === 4) {
            // Draw a differential volume element dV
            const p0 = H * 0.7, phi0 = alpha * 0.6, theta0 = Math.PI / 4;
            const dp = 0.15, dphi = 0.1, dtheta = 0.2;

            const dv_pts = [];
            for(let i=0; i<2; i++) for(let j=0; j<2; j++) for(let k=0; k<2; k++) {
                let p = p0 + i*dp, ph = phi0 + j*dphi, th = theta0 + k*dtheta;
                dv_pts.push({
                    x: p * Math.sin(ph) * Math.cos(th),
                    y: p * Math.sin(ph) * Math.sin(th),
                    z: p * Math.cos(ph)
                });
            }

            data.push({
                type: 'mesh3d',
                x: dv_pts.map(p => p.x), y: dv_pts.map(p => p.y), z: dv_pts.map(p => p.z),
                alphahull: 0,
                color: '#ef4444',
                opacity: 1,
                name: 'dV element'
            });
        }

        const layout = {
            scene: {
                xaxis: { title: 'X', range: [-H, H], backgroundcolor: '#0f172a', gridcolor: '#334155', zerolinecolor: '#475569' },
                yaxis: { title: 'Y', range: [-H, H], backgroundcolor: '#0f172a', gridcolor: '#334155', zerolinecolor: '#475569' },
                zaxis: { title: 'Z', range: [0, H * 1.2], backgroundcolor: '#0f172a', gridcolor: '#334155', zerolinecolor: '#475569' },
                aspectmode: 'cube'
            },
            paper_bgcolor: '#0f172a',
            plot_bgcolor: '#0f172a',
            margin: { l: 0, r: 0, b: 0, t: 0 },
            showlegend: false,
            font: { color: '#f8fafc' }
        };

        if (!this.initialized) {
            window.Plotly.newPlot(this.plotDiv, data, layout);
            this.initialized = true;
        } else {
            window.Plotly.react(this.plotDiv, data, layout);
        }
    }
}
